export default function Badge({
  label, bg, color = '#fff', rotate = 0, y = 800, delay = 0.2,
  style, className, shape = 'marketing', drag = true, hoverBg, href,
  width, height
}: BadgeProps) {
  const currentShape = shapes[shape] || shapes.marketing
  const badgeMask = `url("data:image/svg+xml,%3Csvg viewBox='${currentShape.viewBox}' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='${currentShape.path}'%2F%3E%3C%2Fsvg%3E") alpha no-repeat center/contain`

  return (
    <motion.div
      className={`hidden lg:block ${className || ''}`}
      style={{ position: 'absolute', ...style, zIndex: 10, cursor: 'default' }}
      drag={drag ? true : false}
      dragSnapToOrigin={true}
      dragElastic={0.1}
      dragTransition={{ power: 0.3, timeConstant: 200 }}
      initial={{ opacity: 0.001, y, rotate: 0 }}
      animate={{ opacity: 1, y: 0, rotate }}
      transition={{ type: 'spring', bounce: 0.2, delay, duration: 2 }}
    >
      <a 
        href={href} 
        onClick={(e) => !href && e.preventDefault()}
        style={{ textDecoration: 'none', color: 'inherit', cursor: href ? 'pointer' : 'default' }}
      >
        <div style={{
          position: 'relative',
          width: width || 174,
          height: height || 75,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
        <motion.div 
          style={{
            position: 'absolute', inset: 0,
            backgroundColor: bg,
            WebkitMask: badgeMask,
            mask: badgeMask,
            WebkitMaskSize: '100% 100%',
            maskSize: '100% 100%',
          }}
          whileHover={hoverBg ? { backgroundColor: hoverBg } : {}}
        />
        <span style={{
          position: 'relative', zIndex: 1,
          fontFamily: '"Boldonse",sans-serif',
          fontSize: 16,
          fontWeight: 400,
          color,
          letterSpacing: '0.06em',
          textTransform: 'uppercase',
          textAlign: 'center',
          pointerEvents: 'none',
        }}>
          {label}
        </span>
      </div>
      </a>
    </motion.div>
  )
}
